Hi,

I have an issue with the ref counting of python objects that are passed to C++. 
I have a C++ class `Vector` that the use can inherit from (hence I also have a `PyVector` trampoline class). The user-defined python class should then be passed back to C++ where some actions on this class are performed. Unfortunately, it seems that python takes complete ownership of the class, so that it gets deleted even if the C++ side still needs it.

MFE:

```
#include <pybind11/pybind11.h>
#include <iostream>
#include <memory>

namespace py = pybind11;

class Vector : public std::enable_shared_from_this<Vector> {
    public:
        Vector() {}
        virtual void print() {
            std::cout << "Vector" << std::endl;
        }
};

class PyVector : public Vector {
    public:
        virtual void print() override {
            PYBIND11_OVERLOAD(void, Vector, print,);
        }
};

class Foo {
    public:
        Foo(std::shared_ptr<Vector> vec) : _vec(vec){}
        std::shared_ptr<Vector> _vec;
        void print() {
            _vec -> print();
        }
};

PYBIND11_MODULE(cmake_example, m) {

    py::class_<Vector, std::shared_ptr<Vector>,
        PyVector>(m, "Vector")
            .def(py::init<>());

    py::class_<Foo, std::shared_ptr<Foo>>(m, "Foo")
        .def(py::init<std::shared_ptr<Vector>>())
        .def("print", &Foo::print);

}
```

Python code:
```
import cmake_example as m

class MyVector(m.Vector):

    def print(self):
        print("MyVector")

    def __del__(self):
        print("I was deleted")

def make_foo():
    x = MyVector()
    foo = m.Foo(x)
    foo.print()
    return foo

myfoo = make_foo()
myfoo.print()

```
Output:
```
MyVector
I was deleted
Vector
```
Expected output:
```
MyVector
MyVector
I was deleted
```

I ran into some issues trying to bind a method that returns a const reference to a class member variable. 

With this pybind wrapper:

```C++
#include <pybind11/pybind11.h>
#include <pybind11/stl.h>

class B {};

class A {
public:
    A( const B & b ) : b_(b) {}
    
    const B & b() const { return b_; }
    
protected:
    B b_;
};

namespace py = pybind11;

PYBIND11_PLUGIN(test) {

    py::module m("test", "Test");
    
    py::class_<B>(m, "B")
        .def(py::init<>());
    
    py::class_<A>(m, "A")
        .def(py::init<const B&>(), py::arg("b"))
        .def_property_readonly("b", &A::b);
    
    return m.ptr();
    
}
```
the following python test indicates that method b returns the object it is called on, rather than the contained object b:

```python
import test
b = test.B()
a = test.A(b)
print(a.b)
print(a.b==a)
```
prints: `<test.A at 0x7fee3ad55c70>` and `True`

Any ideas why this is happening?

Consider the following example.
```C++
#include <pybind11/pybind11.h>
#include <iostream>

namespace py = pybind11;
using namespace pybind11::literals;

// classes
class objbase : public std::enable_shared_from_this< objbase > {
	int prop_ = 42;
public:
	virtual std::string name() const {
		return "objbase";
	}

	int prop() const { return prop_; }
};

class iface {
public:
	int n = 84;
	virtual int f() const = 0;
};

class mytype : public iface, public objbase {
public:
	std::string name() const override {
		return "mytype";
	}
	int f() const override {
		return 42;
	}
};
using sp_my = std::shared_ptr<mytype>;

// trampoline
template<class T = objbase>
class py_objbase : public T {
public:
	using T::T;

	std::string name() const override {
		PYBIND11_OVERLOAD(std::string, T, name);
	}
};

class py_iface : public iface {
public:
	using iface::iface;

	int f() const override {
		PYBIND11_OVERLOAD_PURE(int, iface, f);
	}
};

// bind mytype
class py_mytype : public py_iface, public py_objbase<mytype> {
public:
	int f() const override {
		PYBIND11_OVERLOAD(int, mytype, f);
	}
};

PYBIND11_PLUGIN(example) {
	py::module m("example");

	// bind objbase
	py::class_<objbase, py_objbase<>, std::shared_ptr<objbase>>(m, "objbase")
		.def(py::init<>())
		.def("name", &objbase::name)
		.def_property_readonly("prop", &objbase::prop)
		.def_property_readonly("refs", [](objbase& src) { return src.shared_from_this().use_count() - 1; })
	;

	// iface
	py::class_<iface, py_iface, std::shared_ptr<iface>>(m, "iface")
		.def("f", &iface::f)
	;

	// bind mytype
	py::class_<mytype, objbase, py_mytype, std::shared_ptr<mytype>>(m, "mytype")
		.def(py::init<>())
		.def("name", &mytype::name)
		.def("f", &mytype::f)
		.def_property_readonly("n", [](mytype& src){ return src.n; })
	;

	return m.ptr();
}
```
